import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the input length does not exceed buffer size
        char[] buffer = new char[Math.min(name.length(), 10)];
        name.getChars(0, buffer.length, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
